// greedy
class Solution {
public:
    long long minOperations(vector<int>& nums1, vector<int>& nums2, int k) {
        int64_t cnt1 = 0, cnt2 = 0;
        for (int i = 0; i < size(nums1); ++i) {
            if (nums1[i] == nums2[i]) {
                continue;
            }
            if (k == 0 || (nums1[i] - nums2[i]) % k) {
                return -1;
            }
            if (nums1[i] < nums2[i]) {
                cnt1 += static_cast<int64_t>(nums2[i] - nums1[i]) / k;
            } else {
                cnt2 += static_cast<int64_t>(nums1[i] - nums2[i]) / k;
            }
        }
        return cnt1 == cnt2 ? cnt1 : -1;
    }
};

# Time:  O(n)
# Space: O(1)

import itertools


# greedy
class Solution(object):
    def minOperations(self, nums1, nums2, k):
        """
        :type nums1: List[int]
        :type nums2: List[int]
        :type k: int
        :rtype: int
        """
        cnt1 = cnt2 = 0
        for x, y in itertools.izip(nums1, nums2):
            if y == x:
                continue
            if k == 0 or (y-x)%k:
                return -1
            if x < y:
                cnt1 += (y-x)//k
            else:
                cnt2 += (x-y)//k
        return cnt1 if cnt1 == cnt2 else -1
